mapper.select:
SELECT m.message_id, m.account_id, m.provider, m.provider_message_id, m.internet_message_id, m.thread_id, m.folder, m.direction, m.subject, m.from_name, m.from_address, m.to_addresses, m.cc_addresses, m.sent_time, m.received_time, m.body_sync_mode, m.body_sync_status, m.summary, m.keywords, m.intent, m.action_items_json, m.reply_deadline_time, m.extraction_status, LEFT(COALESCE(m.body_text, ''), 1200) AS body_text, m.has_attachments, m.read_status, m.starred, m.deleted, m.customer_id, c.company_name AS customer_name, m.contact_id, ct.name AS contact_name, m.knowledge_id, m.create_time FROM crm_mail_message m LEFT JOIN crm_customer c ON m.customer_id = c.customer_id LEFT JOIN crm_contact ct ON m.contact_id = ct.contact_id WHERE m.tenant_id = #{tenantId} AND m.user_id = #{userId} AND COALESCE(m.deleted, FALSE) = FALSE
AND m.account_id = #{query.accountId}
AND m.customer_id = #{query.customerId}
AND LOWER(m.folder) = LOWER(#{query.folder})
AND LOWER(m.direction) = LOWER(#{query.direction})
AND LOWER(m.read_status) = LOWER(#{query.readStatus})
AND COALESCE(m.starred, FALSE) = #{query.starred}
AND ( m.subject ILIKE CONCAT('%', #{query.keyword}, '%') OR m.from_address ILIKE CONCAT('%', #{query.keyword}, '%') OR m.to_addresses ILIKE CONCAT('%', #{query.keyword}, '%') OR m.body_text ILIKE CONCAT('%', #{query.keyword}, '%') OR m.summary ILIKE CONCAT('%', #{query.keyword}, '%') OR m.keywords ILIKE CONCAT('%', #{query.keyword}, '%') )
AND COALESCE(m.received_time, m.sent_time, m.create_time) >= #{query.startTime}
AND COALESCE(m.received_time, m.sent_time, m.create_time) <= #{query.endTime}
ORDER BY COALESCE(m.received_time, m.sent_time, m.create_time) DESC

SELECT m.message_id, m.account_id, m.provider, m.provider_message_id, m.internet_message_id, m.thread_id, m.folder, m.direction, m.subject, m.from_name, m.from_address, m.to_addresses, m.cc_addresses, m.sent_time, m.received_time, m.body_sync_mode, m.body_sync_status, m.summary, m.keywords, m.intent, m.action_items_json, m.reply_deadline_time, m.extraction_status, LEFT(COALESCE(m.body_text, ''), 2000) AS body_text, m.has_attachments, m.read_status, m.starred, m.deleted, m.customer_id, c.company_name AS customer_name, m.contact_id, ct.name AS contact_name, m.knowledge_id, m.create_time FROM crm_mail_message m LEFT JOIN crm_customer c ON m.customer_id = c.customer_id LEFT JOIN crm_contact ct ON m.contact_id = ct.contact_id WHERE m.tenant_id = #{tenantId} AND m.user_id = #{userId} AND m.account_id = #{accountId} AND COALESCE(m.deleted, FALSE) = FALSE
AND m.thread_id = #{threadId}
AND m.message_id = #{fallbackMessageId}
ORDER BY COALESCE(m.received_time, m.sent_time, m.create_time) ASC
